class Solution:
    def minCostToEqualizeArray(self, nums, cost1: int, cost2: int) -> int:
        MOD = 10**9 + 7
        n = len(nums)
        if n == 1:
            return 0
        mx = max(nums)
        mn = min(nums)
        s = sum(nums)

        if 2 * cost1 <= cost2:
            return (mx * n - s) * cost1 % MOD

        bound = max(mx, s - 2 * mn) + 1
        best = float('inf')
        for target in range(mx, bound + 1):
            total = target * n - s
            max_d = target - mn
            rest = total - max_d
            if max_d > rest:
                cost = rest * cost2 + (max_d - rest) * cost1
            else:
                cost = (total // 2) * cost2 + (total % 2) * cost1
            best = min(best, cost)
        return best % MOD

