var minCostToEqualizeArray = function(nums, cost1, cost2) {
    const MOD = 1000000007n;
    const n = nums.length;
    if (n === 1) return 0;
    const mx = Math.max(...nums);
    const mn = Math.min(...nums);
    const s = nums.reduce((a, b) => a + b, 0);

    if (2 * cost1 <= cost2) {
        return Number(BigInt(mx * n - s) * BigInt(cost1) % MOD);
    }

    const bound = Math.max(mx, s - 2 * mn) + 1;
    let best = Infinity;
    for (let target = mx; target <= bound; target++) {
        const total = target * n - s;
        const maxD = target - mn;
        const rest = total - maxD;
        let cost;
        if (maxD > rest) {
            cost = rest * cost2 + (maxD - rest) * cost1;
        } else {
            cost = Math.floor(total / 2) * cost2 + (total % 2) * cost1;
        }
        if (cost < best) best = cost;
    }
    return Number(BigInt(best) % MOD);
};
